WHERE s.is_deleted = FALSE

    AND s.region = #{region}


    AND s.city_id = #{cityId}


    AND s.area_id = #{areaId}


    AND s.category_id = #{categoryId}


    AND (
        LOWER(s.name) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        OR LOWER(s.address) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        OR LOWER(m.company_name) LIKE CONCAT('%', LOWER(#{keyword}), '%')
    )

mapper.update:
UPDATE shop
SET is_deleted = TRUE,
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{shopId}
  AND region = #{region}
  AND is_deleted = FALSE
